practice_tasks.starter_code:
SELECT name, salary
FROM employees
ORDER BY salary DESC;

practice_tasks.solution:
SELECT name, salary, ROW_NUMBER() OVER (ORDER BY salary DESC) AS salary_rank
FROM employees
ORDER BY salary DESC;

challenge.solution:
SELECT name, department, salary, RANK() OVER (PARTITION BY department ORDER BY salary DESC) AS dept_rank
FROM employees
ORDER BY department, dept_rank;
